import numpy as np

def compute_weights(n: int) -> np.ndarray:
    if n == 0:
        return np.array([])
    # Rank from 0 (worst) to n-1 (best)
    ranks = np.arange(n)
    # Temperature decreases with n, tightening focus on best points as group grows
    temperature = max(1.0, n / 5.0)
    weights = np.exp(ranks / temperature)
    return weights

import numpy as np

def compute_weights(n: int) -> np.ndarray:
    if n == 0:
        return np.array([])
    # Exponential decay: weight ~ exp(-alpha * (n-1-i)) for i from 0 (worst) to n-1 (best)
    # alpha increases with n to focus more on top performers as more data accumulates
    alpha = 0.5 + 0.2 * np.log(n + 1)
    indices = np.arange(n)
    weights = np.exp(-alpha * (n - 1 - indices))
    return weights
